parameters.jsCode:
const raw = $input.first().json.output;

// Parse the stringified JSON from AI Agent
const analysis = JSON.parse(raw);

// Pull HTTP Request data once
const httpData = $('HTTP Request').first().json;

// candidate_id and cv_evaluation_id come from the HTTP call metadata
const candidateId = httpData?.metadata?.candidate_id ?? null;
const cvEvalId    = httpData?.metadata?.cv_evaluation_id ?? null;

return [{
  json: {
    // AI Analysis fields
    overall_sentiment:        analysis.overall_sentiment,
    candidate_interest_level: analysis.candidate_interest_level,
    availability_confirmed:   analysis.availability_confirmed,
    proposed_interview_slots: analysis.proposed_interview_slots,
    candidate_concerns:       analysis.candidate_concerns,
    key_highlights:           analysis.key_highlights,
    recommended_action:       analysis.recommended_action,
    confidence_score:         analysis.confidence_score,
    summary:                  analysis.summary,

    // Pass-through context for the Supabase node
    candidate_id:          candidateId,
    cv_evaluation_id:      cvEvalId,
    invite_id:             null,
    retell_call_id:        httpData.call_id,
    call_duration_seconds: Math.round((httpData.duration_ms ?? 0) / 1000),
    transcript:            httpData.transcript    ?? null,
    recording_url:         httpData.recording_url ?? null,
    completed_at:          httpData.end_timestamp
                             ? new Date(httpData.end_timestamp).toISOString()
                             : null,
  }
}];

